   585→func mutateSampleLabels(lset labels.Labels, target *Target, honor bool, rc []*relabel.Config) labels.Labels {
   586→	lb := labels.NewBuilder(lset)
   587→
   588→	if honor {
   589→		target.LabelsRange(func(l labels.Label) {
   590→			if !lset.Has(l.Name) {
   591→				lb.Set(l.Name, l.Value)
   592→			}
   593→		})
   594→	} else {
   595→		var conflictingExposedLabels []labels.Label
   596→		target.LabelsRange(func(l labels.Label) {
   597→			existingValue := lset.Get(l.Name)
   598→			if existingValue != "" {
   599→				conflictingExposedLabels = append(conflictingExposedLabels, labels.Label{Name: l.Name, Value: existingValue})
   600→			}
   601→			// It is now safe to set the target label.
   602→			lb.Set(l.Name, l.Value)
   603→		})
   604→
   605→		if len(conflictingExposedLabels) > 0 {
   606→			resolveConflictingExposedLabels(lb, conflictingExposedLabels)
   607→		}
   608→	}
   609→
   610→	if keep := relabel.ProcessBuilder(lb, rc...); !keep {
   611→		return labels.EmptyLabels()
   612→	}
   613→
   614→	return lb.Labels()
   615→}
   616→
   617→func resolveConflictingExposedLabels(lb *labels.Builder, conflictingExposedLabels []labels.Label) {
   618→	slices.SortStableFunc(conflictingExposedLabels, func(a, b labels.Label) int {
   619→		return len(a.Name) - len(b.Name)
   620→	})
   621→
   622→	for _, l := range conflictingExposedLabels {
   623→		newName := l.Name
   624→		for {
   625→			newName = model.ExportedLabelPrefix + newName
   626→			if lb.Get(newName) == "" {
   627→				lb.Set(newName, l.Value)
   628→				break
   629→			}
   630→		}
   631→	}
   632→}
   633→
   634→func mutateReportSampleLabels(lset labels.Labels, target *Target) labels.Labels {
   635→	lb := labels.NewBuilder(lset)
   636→
   637→	target.LabelsRange(func(l labels.Label) {
   638→		lb.Set(model.ExportedLabelPrefix+l.Name, lset.Get(l.Name))
   639→		lb.Set(l.Name, l.Value)
   640→	})
   641→
   642→	return lb.Labels()
   643→}
