   645→// appenderWithLimits returns an appender with additional validation.
   646→func appenderWithLimits(app storage.Appender, sampleLimit, bucketLimit int, maxSchema int32) storage.Appender {
   647→	app = &timeLimitAppender{
   648→		Appender: app,
   649→		maxTime:  timestamp.FromTime(time.Now().Add(maxAheadTime)),
   650→	}
   651→
   652→	// The sampleLimit is applied after metrics are potentially dropped via relabeling.
   653→	if sampleLimit > 0 {
   654→		app = &limitAppender{
   655→			Appender: app,
   656→			limit:    sampleLimit,
   657→		}
   658→	}
   659→
   660→	if bucketLimit > 0 {
   661→		app = &bucketLimitAppender{
   662→			Appender: app,
   663→			limit:    bucketLimit,
   664→		}
   665→	}
   666→
   667→	if maxSchema < histogram.ExponentialSchemaMax {
   668→		app = &maxSchemaAppender{
   669→			Appender:  app,
   670→			maxSchema: maxSchema,
   671→		}
   672→	}
   673→
   674→	return app
   675→}
