  1234→func (sl *scrapeLoop) run(errc chan<- error) {
  1235→	if !sl.skipOffsetting {
  1236→		select {
  1237→		case <-time.After(sl.scraper.offset(sl.interval, sl.offsetSeed)):
  1238→			// Continue after a scraping offset.
  1239→		case <-sl.ctx.Done():
  1240→			close(sl.stopped)
  1241→			return
  1242→		}
  1243→	}
  1244→
  1245→	var last time.Time
  1246→
  1247→	alignedScrapeTime := time.Now().Round(0)
  1248→	ticker := time.NewTicker(sl.interval)
  1249→	defer ticker.Stop()
  1250→
  1251→mainLoop:
  1252→	for {
  1253→		select {
  1254→		case <-sl.parentCtx.Done():
  1255→			close(sl.stopped)
  1256→			return
  1257→		case <-sl.ctx.Done():
  1258→			break mainLoop
  1259→		default:
  1260→		}
  1261→
  1262→		// Temporary workaround for a jitter in go timers that causes disk space
  1263→		// increase in TSDB.
  1264→		// See https://github.com/prometheus/prometheus/issues/7846
  1265→		// Calling Round ensures the time used is the wall clock, as otherwise .Sub
  1266→		// and .Add on time.Time behave differently (see time package docs).
  1267→		scrapeTime := time.Now().Round(0)
  1268→		if AlignScrapeTimestamps {
  1269→			// Tolerance is clamped to maximum 1% of the scrape interval.
  1270→			tolerance := min(sl.interval/100, ScrapeTimestampTolerance)
  1271→			// For some reason, a tick might have been skipped, in which case we
  1272→			// would call alignedScrapeTime.Add(interval) multiple times.
  1273→			for scrapeTime.Sub(alignedScrapeTime) >= sl.interval {
  1274→				alignedScrapeTime = alignedScrapeTime.Add(sl.interval)
  1275→			}
  1276→			// Align the scrape time if we are in the tolerance boundaries.
  1277→			if scrapeTime.Sub(alignedScrapeTime) <= tolerance {
  1278→				scrapeTime = alignedScrapeTime
  1279→			}
  1280→		}
  1281→
  1282→		last = sl.scrapeAndReport(last, scrapeTime, errc)
  1283→
  1284→		select {
  1285→		case <-sl.parentCtx.Done():
  1286→			close(sl.stopped)
  1287→			return
  1288→		case <-sl.ctx.Done():
  1289→			break mainLoop
  1290→		case <-ticker.C:
  1291→		}
  1292→	}
  1293→
  1294→	close(sl.stopped)
  1295→
  1296→	if !sl.disabledEndOfRunStalenessMarkers.Load() {
  1297→		sl.endOfRunStaleness(last, ticker, sl.interval)
  1298→	}
  1299→}
