### 8. **Counter and Gauge Metrics Internal Tracking**

**Counter implementation:**

**File: `~/workspace/go/agent-index-go/testdata/fixtures/go/prom_counter.go` (lines 103-144)**

```go
type counter struct {
	// Two separate tracking variables for optimal performance
	valBits uint64  // Tracks float64 additions as bits
	valInt  uint64  // Tracks integer increments

	selfCollector
	desc *Desc
	createdTs  *timestamppb.Timestamp
	labelPairs []*dto.LabelPair
	exemplar   atomic.Value
	now func() time.Time
}

func (c *counter) Add(v float64) {
	if v < 0 {
		panic(errors.New("counter cannot decrease in value"))
	}

	// Try to convert to uint64 for atomic increment
	ival := uint64(v)
	if float64(ival) == v {
		atomic.AddUint64(&c.valInt, ival)
		return
	}

	// For non-integer floats, use compare-and-swap loop
	for {
		oldBits := atomic.LoadUint64(&c.valBits)
		newBits := math.Float64bits(math.Float64frombits(oldBits) + v)
		if atomic.CompareAndSwapUint64(&c.valBits, oldBits, newBits) {
			return
		}
	}
}

func (c *counter) Inc() {
	atomic.AddUint64(&c.valInt, 1)
}

func (c *counter) get() float64 {
	fval := math.Float64frombits(atomic.LoadUint64(&c.valBits))
	ival := atomic.LoadUint64(&c.valInt)
	return fval + float64(ival)
}

func (c *counter) Write(out *dto.Metric) error {
	var exemplar *dto.Exemplar
	if e := c.exemplar.Load(); e != nil {
		exemplar = e.(*dto.Exemplar)
	}
	val := c.get()
	return populateMetric(CounterValue, val, c.labelPairs, exemplar, out, c.createdTs)
}
```

**Gauge implementation:**

**File: `~/workspace/go/agent-index-go/testdata/fixtures/go/prom_gauge.go` (lines 90-139)**

```go
type gauge struct {
	// Single tracking value, optimized for Set() operations
	valBits uint64

	selfCollector
	desc       *Desc
	labelPairs []*dto.LabelPair
}

func (g *gauge) Set(val float64) {
	atomic.StoreUint64(&g.valBits, math.Float64bits(val))
}

func (g *gauge) Add(val float64) {
	for {
		oldBits := atomic.LoadUint64(&g.valBits)
		newBits := math.Float64bits(math.Float64frombits(oldBits) + val)
		if atomic.CompareAndSwapUint64(&g.valBits, oldBits, newBits) {
			return
		}
	}
}

func (g *gauge) Write(out *dto.Metric) error {
	val := math.Float64frombits(atomic.LoadUint64(&g.valBits))
	return populateMetric(GaugeValue, val, g.labelPairs, nil, out, nil)
}
```

**Key differences:**
- **Counters** track two values (`valBits` for floats, `valInt` for integers) for performance
- **Gauges** track one value optimized for the `Set()` operation
- Both use atomic operations to ensure thread-safety without locks
- Values are stored as float64 bits for atomic operations

